    pub fn recovery_idv_sessions(&self) -> RecoveryIdvSessionRepo<'a> {
        RecoveryIdvSessionRepo {
            store: self.store,
            scope: self.scope,
        }
    }

    /// The read-only risk-engine repository for this scope (issue #79): read a subject's
